_COMPOUND_MARKERS = re.compile(
    r'\b(?:then|and then|after that)\b|;|->|→',
    re.IGNORECASE,
)


def _is_compound_request(text: str) -> bool:
    """True if the request has multi-step conjunctions."""
    return bool(_COMPOUND_MARKERS.search(text))


